2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.10;
5	
6	const BLOCK_OF_THREE_PRICE = 60;
7	const CURSED_SURCHARGE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	
11	const BASE_PRICE: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	function surchargeFor(item: PolicyItem): number {
21	  let surcharge = 0;
22	  if (item.cursed) {
23	    surcharge += BASE_PRICE[item.type] * CURSED_SURCHARGE_RATE;
24	  }
25	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
26	    surcharge += BASE_PRICE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
27	  }
28	  return surcharge;
29	}
30	
31	function itemPremium(items: PolicyItem[]): number {
32	  const countsByType: Record<string, number> = {};
33	  for (const item of items) {
34	    countsByType[item.type] = (countsByType[item.type] || 0) + 1;
35	  }
36	
37	  let itemTotal = 0;
38	  for (const type in countsByType) {
39	    const count = countsByType[type];
40	    const isBlockOfThree = count === 3;
41	    if (isBlockOfThree) {
42	      itemTotal += BLOCK_OF_THREE_PRICE;
43	    } else {
44	      itemTotal += count * BASE_PRICE[type];
45	    }
46	  }
47	
48	  for (const item of items) {
49	    itemTotal += surchargeFor(item);
50	  }
51	
52	  return itemTotal;
53	}
54	
55	const LOYALTY_DISCOUNT_RATE = 0.2;
56	const LOYALTY_THRESHOLD_YEARS = 2;
57	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
58	
59	export function quote(
60	  policy: { customer: { years: number }; items: PolicyItem[] },
61	  options: { isFollowUp: boolean }
62	): { premium: number } {
63	  const policyBase = itemPremium(policy.items);
64	  let premium = policyBase;
65	  premium += policyBase * FIRST_INSURANCE_RATE;
66	  if (policy.customer.years >= LOYALTY_THRESHOLD_YEARS) {
67	    premium -= policyBase * LOYALTY_DISCOUNT_RATE;
68	  }
69	  if (options.isFollowUp) {
70	    premium -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
71	  }
72	  return { premium: Math.ceil(premium + PROCESSING_FEE) };
73	}
